package csv

import "strings"

func ParseLine(line string) []string {
	var fields []string
	var current strings.Builder
	inQuotes := false

	for i := 0; i < len(line); i++ {
		ch := line[i]
		if inQuotes {
			if ch == '"' {
				// Check for escaped quote ("")
				if i+1 < len(line) && line[i+1] == '"' {
					current.WriteByte('"')
					i++ // skip next quote
				} else {
					inQuotes = false
				}
			} else {
				current.WriteByte(ch)
			}
		} else {
			if ch == '"' {
				inQuotes = true
			} else if ch == ',' {
				fields = append(fields, current.String())
				current.Reset()
			} else {
				current.WriteByte(ch)
			}
		}
	}
	fields = append(fields, current.String())
	return fields
}
